    fst = fst.determinize().minimize()
    print("paths: %d   states: %d" % (len(paths), len(fst.states)))
    return fst


def main():
    fst = build()
    foma_str = fst.to_fomastring()
    with open(OUT_FOMA, "w", encoding="utf-8") as fh:
        fh.write(foma_str)
    print("wrote %s" % OUT_FOMA)


if __name__ == "__main__":
    main()

