# Suffixation.
# ----------------------------------------------------------------------------
def add_imp(stem):
    stem = denorm(stem)
    u = units(stem)
    last = u[-1]
    if last == "s̥":                       # s̥ -> s before the -iñ imperative
        return "".join(u[:-1]) + "siñ"
    return stem + "ñ" if isvow(last) else stem + "iñ"


def fut(stem):
    stem = denorm(stem)
    u = units(stem)
