# codepoint classes for the general (rule-based) transducer
VOWEL_CP = set("aeiouAO:")          # ':' (length) behaves as a vowel
BREVE_CP = "̆"                       # U+0306 combining breve (whispered vowel)


def build_general(chars):
    """A rule-based transducer that inflects ANY lemma over the alphabet.
    Used only for lemmas absent from the training lexicon."""
    cons = [c for c in chars if c not in VOWEL_CP and c != BREVE_CP]
    vowels = [c for c in chars if c in VOWEL_CP]

    def cls(members):
        return "(" + "|".join("'%s':'%s'" % (esc(c), esc(c)) for c in members) + ")"

    ANY = cls(chars) + "*"                      # identity copy of any string
    ENDVOW = ANY + " " + cls(vowels)            # ...vowel  (plain vowel final)
    ENDCONS = ANY + " " + cls(cons)             # ...consonant final
    ENDBREVE = ANY + " '%s':''" % esc(BREVE_CP)  # ...breve -> drop breve
    DELCONS = ANY + " (" + "|".join("'%s':''" % esc(c) for c in cons) + ")"

    def stem(kind):
        if kind == "id":
            return ANY
        if kind == "fut":
            return "( %s '':'d' | %s '':'d' | %s '':'ad' )" % (ENDVOW, ENDBREVE, ENDCONS)
        if kind == "imp":
            return "( %s '':'ñ' | %s '':'ñ' | %s '':'iñ' )" % (ENDVOW, ENDBREVE, ENDCONS)
        if kind == "prf":
            # ends in a vowel/breve -> unchanged; else drop final consonant
            return "( %s | %s '%s':'%s' | %s )" % (ENDVOW, ANY, esc(BREVE_CP), esc(BREVE_CP), DELCONS)
        raise ValueError(kind)

    alts = []
    for feat in ALL_COMBOS:
        fp = " ".join("'[%s]':'[%s]'" % (esc(t), esc(t)) for t in feat.split(";"))
        alts.append("%s ( %s )" % (fp, stem(TRANSFORM[feat])))
    return FST.re(" | ".join(alts)).determinize().minimize()


def build():
    lem = collections.defaultdict(dict)
    pos = collections.defaultdict(set)
    with open(TRAIN, encoding="utf-8") as fh:
        for line in fh:
            line = line.rstrip("\n")
            if not line:
                continue
            lemma, wf, feat = line.split("\t")
            lem[lemma][feat] = wf
            pos[lemma].add(feat.split(";")[0])

    chars = set()
    for lemma, forms in lem.items():
        chars.update(lemma)
        for w in forms.values():
            chars.update(w)

    paths = []
    for lemma, forms in lem.items():
        combos = []
        if "N" in pos[lemma]:
            combos += N_COMBOS
        if "V" in pos[lemma]:
            combos += V_COMBOS
        for feat in combos:
            out = forms[feat] if feat in forms else predict(feat, forms)
            if out is None:
                continue
            fa = atoms_feat(feat)
            src = " ".join(fa + atoms_word(lemma))
            dst = " ".join(fa + atoms_word(out))
            paths.append("(%s):(%s)" % (src, dst))

    # --- memorized per-lemma paradigm (M) ---------------------------------
    # A single huge alternation is pathologically slow to parse, so compile in
    # modest batches, then union + minimize.
    BATCH = 150
    fsts = [FST.re(" | ".join(paths[i:i + BATCH]))
            for i in range(0, len(paths), BATCH)]
    M = fsts[0]
    for g in fsts[1:]:
        M = M.union(g)
    M = M.determinize().minimize()

    # --- general rule-based fallback (G), used only where M has no path ----
    G = build_general(chars)

    # All symbols in play: feature tags + characters.
    tag_syms = set()
    for feat in ALL_COMBOS:
        tag_syms.update("[%s]" % t for t in feat.split(";"))
    sigma = sorted(tag_syms | chars)
    sigma_star = FST.re("(" + "|".join("'%s'" % esc(s) for s in sigma) + ")*")

    dom_M = M.project(dim=0)                     # input language covered by M
    not_M = sigma_star.difference(dom_M)          # inputs M does NOT cover
    G_only = not_M.compose(G)                      # restrict G to those inputs
    fst = M.union(G_only).determinize().minimize()

    print("paths: %d   M-states: %d   G-states: %d   final-states: %d"
          % (len(paths), len(M.states), len(G.states), len(fst.states)))
    return fst


def main():
    fst = build()
    foma_str = fst.to_fomastring()
    with open(OUT_FOMA, "w", encoding="utf-8") as fh:
        fh.write(foma_str)
    print("wrote %s" % OUT_FOMA)


if __name__ == "__main__":
    main()

